            array('id' => '107','page_id' => '1','hints' => 'about-section','title' => 'Welcome to WH Doctors Study Lab Ltd','subtitle' => 'Know your study before starting','image' => NULL,'description' => '<p>WH Doctor Study Lab is an overseas education consulting firm that helps students study abroad. Through the WH Doctor Study Lab, overseas intending students can study in the UK, USA, Canada and Australia. The experienced team at WH Doctor Study Lab offers authentic and resourceful information and solutions to students interested in studying abroad. The experienced and well-trained counsellors at WH Doctor Study Lab are dedicated to offering multiple services and help to the students whenever they need it. They have real-life experience studying abroad. Moreover, they get training from the experts to stay up-to-date with their knowledge.</p>','number' => NULL,'button_text' => NULL,'button_link' => NULL,'is_not_deleteable' => '0','active_status' => '1','created_at' => '2023-11-16 06:28:28','updated_at' => '2024-02-20 23:31:25'),
